parameters.jsCode:
const item = $input.item.json;
const d = new Date(item.scheduled_at);
const pad = n => String(n).padStart(2, '0');
const dateStr = pad(d.getDate()) + '/' + pad(d.getMonth()+1) + '/' + d.getFullYear();
const timeStr = pad(d.getHours()) + ':' + pad(d.getMinutes());
const qrData = 'CITA PSICOLOGICA
Paciente: ' + item.first_name + ' ' + item.last_name + '
Fecha: ' + dateStr + '
Hora: ' + timeStr + ' hs
Tipo: ' + item.appointment_type + '
Duracion: ' + item.duration_minutes + ' min
Psicologo: ' + (item.psychologist_name || '');
const qrUrl = 'https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=' + encodeURIComponent(qrData);
const message = 'Recordatorio de cita

Hola ' + item.first_name + ', te recordamos que tenes una cita manana:

Fecha: ' + dateStr + ' a las ' + timeStr + ' hs
Tipo: ' + item.appointment_type + '
Duracion: ' + item.duration_minutes + ' min
Psicologo: ' + (item.psychologist_name || '') + '

Escaneá el QR para ver los detalles de tu cita:
' + qrUrl;
return { json: { ...item, qrUrl, message } };
